code = """import json
import pandas as pd

# Load the datasets
cases = locals().get('var_functions.query_db:38', [])
history_cases = locals().get('var_functions.query_db:36', [])

print('Cases in main query: ' + str(len(cases)))
print('Cases in history: ' + str(len(history_cases)))

# Extract case IDs
main_case_ids = [case['id'].lstrip('#') for case in cases]
history_case_ids = [case['caseid__c'].lstrip('#') for case in history_cases]

print('Main case IDs: ' + str(main_case_ids))
print('History case IDs: ' + str(history_case_ids))

# Find missing cases from main query
missing_ids = set(history_case_ids) - set(main_case_ids)
print('Missing case IDs: ' + str(missing_ids))
print('Number missing: ' + str(len(missing_ids)))

# Build a query for the missing cases
if missing_ids:
    # Build IN clause
    id_list = "','".join(missing_ids)
    in_clause = "('" + id_list + "')"
    query = "SELECT id, ownerid, createddate, closeddate FROM \"Case\" WHERE id IN " + in_clause + " AND createddate >= '2023-05-02' AND createddate <= '2023-09-02' AND closeddate IS NOT NULL;"
    print('Query for missing cases: ' + query)
    
    # Build result to pass to next step
    result = {"query": query, "missing_count": len(missing_ids)}
    print('__RESULT__:')
    print(json.dumps(result))
else:
    print('__RESULT__:')
    print(json.dumps({"query": "", "missing_count": 0}))"""

